const GTFS_CAL_EX = {"20260629":{"F":1,"D":1,"L":2},"20260716":{"F":1,"D":1,"L":2},"20260815":{"F":1,"D":1,"S":2},"20260918":{"F":1,"D":1,"L":2},"20260919":{"F":1,"D":1,"S":2},"20261012":{"F":1,"D":1,"L":2},"20261031":{"F":1,"D":1,"S":2},"20261208":{"F":1,"D":1,"L":2},"20261225":{"F":1,"D":1,"L":2}};

/* ----------------------------------------------------------
   getTodayService()
   Determina L / S / D considerando festivos del GTFS.
   ---------------------------------------------------------- */
function getTodayService() {
  const now    = new Date();
  const dow    = now.getDay();
  const y      = now.getFullYear();
  const m      = String(now.getMonth()+1).padStart(2,'0');
  const d      = String(now.getDate()).padStart(2,'0');
  const dateStr = y + m + d;

  let serviceId = dow === 0 ? 'D' : dow === 6 ? 'S' : 'L';
  let label     = dow === 0 ? 'Domingo' : dow === 6 ? 'Sábado' : 'Día hábil';

  const exDay = GTFS_CAL_EX[dateStr];
  if (exDay) {
    if (exDay['F'] === 1 || (exDay['D'] === 1 && exDay['L'] === 2)) {
      serviceId = 'D'; label = 'Festivo (opera como Domingo)';
    } else if (exDay['S'] === 1) {
      serviceId = 'S'; label = 'Festivo (opera como Sábado)';
    }
  }
  return { serviceId, label };
}

/* ----------------------------------------------------------
   getCurrentFrequency(routeId)
   Retorna la franja horaria activa y headway para una ruta.
   ---------------------------------------------------------- */
function getCurrentFrequency(routeId) {
  const rid = (routeId || '').toUpperCase();
  const svc = getTodayService();
  const routeFreqs = GTFS_FREQ[rid];

  if (!routeFreqs) {
    return { operates: false, serviceLabel: svc.label, serviceId: svc.serviceId, reason: 'sin datos de frecuencia' };
  }

  const slots = routeFreqs[svc.serviceId];
  if (!slots || slots.length === 0) {
    return { operates: false, serviceLabel: svc.label, serviceId: svc.serviceId, reason: 'sin servicio programado hoy' };
  }

  const fmt    = mn => String(Math.floor(mn/60)).padStart(2,'0') + ':' + String(mn%60).padStart(2,'0');
  const now    = new Date();
  const nowMin = now.getHours() * 60 + now.getMinutes();
  const active = slots.find(([s, e]) => nowMin >= s && nowMin < e);

  if (!active) {
    const next = slots.find(([s]) => s > nowMin);
    if (next) {
      return {
        operates: true, outOfService: true,
        nextStart: fmt(next[0]),
        headwaySecs: next[2], headwayMin: Math.round(next[2]/60),
        serviceId: svc.serviceId, serviceLabel: svc.label
      };
    }
    return { operates: false, serviceLabel: svc.label, serviceId: svc.serviceId, reason: 'fuera de horario operativo' };
  }

  const hw = active[2];
  const hwMin = Math.round(hw / 60);
  const hwLabel = hw < 120
    ? hw + 's'
    : (Math.floor(hw/60) + 'min' + (hw%60 > 0 ? String(hw%60).padStart(2,'0')+'s' : ''));

  return {
    operates: true, outOfService: false,
    headwaySecs: hw, headwayMin: hwMin, headwayLabel: hwLabel,
    startTime: fmt(active[0]), endTime: fmt(active[1]),
    serviceId: svc.serviceId, serviceLabel: svc.label
  };
}

/* ----------------------------------------------------------
   assessDelay(routeId)
   Evalúa gravedad del retraso según headway programado.
   Un "Retraso significativo" = superar 1 headway sin paso.
   ---------------------------------------------------------- */
function assessDelay(routeId) {
  const freq = getCurrentFrequency(routeId);
  if (!freq.operates) {
    return { severity: null, freq, message: freq.reason };
  }
  if (freq.outOfService) {
    return { severity: 'Baja', freq, message: 'Recorrido fuera de horario activo. Próxima salida: ' + freq.nextStart };
  }
  const hw = freq.headwayMin;
  // Lógica: a menor headway programado, mayor impacto del retraso
  const severity = hw <= 8 ? 'Alta' : hw <= 14 ? 'Media' : 'Baja';
  return {
    severity,
    freq,
    message: 'Frecuencia programada: cada ' + hw + ' min (' + freq.startTime + '\u2013' + freq.endTime + ', ' + freq.serviceLabel + ')'
  };
}
